function toLineData(series: Series): LineData[] {
  const out: LineData[] = [];
  for (let i = 0; i < series.time.length; i++) {
    const v = series.values[i];
    if (v != null) {
      out.push({ time: series.time[i] as UTCTimestamp, value: v });
    }
  }
  return out;
}

