    chartRef.current?.timeScale().fitContent();
  }, [candles]);

  // Compute and render overlays whenever candles or indicator config change.
  useEffect(() => {
    let cancelled = false;
    const chart = chartRef.current;
    if (!chart || candles.length === 0) return;

