    overlayRefs.current.forEach((s) => chart.removeSeries(s));
    overlayRefs.current = [];

    (async () => {
      try {
        setOverlayError(null);
        for (const ind of indicators) {
          if (!ind.enabled) continue;
          if (ind.kind === 'sma' || ind.kind === 'ema') {
            const series =
