  it('groups consecutive days into fixed 7-day weekly buckets', () => {
    const t0 = Date.UTC(2024, 0, 1) / 1000;
    const sameWeek = bucketKey(t0, '1W') === bucketKey(t0 + 6 * DAY, '1W');
    const nextWeek = bucketKey(t0, '1W') !== bucketKey(t0 + 7 * DAY, '1W');
