const DAY = 86_400;

/** Builds N consecutive daily candles starting at a fixed UTC date. */
function dailyCandles(n: number, start = Date.UTC(2024, 0, 1) / 1000): Candle[] {
  const out: Candle[] = [];
  for (let i = 0; i < n; i++) {
    const base = 100 + i;
    out.push({
      time: start + i * DAY,
      open: base,
      high: base + 2,
      low: base - 2,
      close: base + 1,
      volume: 1000,
    });
  }
  return out;
}

