  const now = Math.floor(Date.now() / 1000);
  const daySecs = 86_400;
  const startTime = now - days * daySecs;

  for (let i = 0; i < days; i++) {
    const drift = 0.0003;
    const vol = 0.018;
    const shock = (rand() - 0.5) * 2;
    const ret = drift + vol * shock;
    const open = price;
    const close = Math.max(1, open * (1 + ret));
